public class Main {
    static int count = 0;
    static int divide(int a, int b) {
        try {
            return a / b;
        } catch (ArithmeticException e) {
            return -1;
        } finally {
            count++;
        }
    }
    public static void main(String[] args) {
        System.out.print(divide(10, 2) + " ");
        System.out.print(divide(10, 0) + " ");
        System.out.print(count);
    }
}

